        conn,
        run_id,
        phase_number,
        phase_name,
        &status.to_string(),
        iteration,
        budget,
    )
    .await
}

pub async fn get_pipeline_phases(conn: &Connection, run_id: i64) -> Result<Vec<PipelinePhase>> {
