            .method("POST")
            .uri("/api/issues/1/run")
            .body(Body::empty())
            .unwrap();
        app.clone().oneshot(trigger).await.unwrap();

        // Cancel the pipeline run
        let request = Request::builder()
            .method("POST")
            .uri("/api/runs/1/cancel")
            .body(Body::empty())
            .unwrap();

