137→            }
138→            FactoryError::RunNotFound { id } => {
139→                ApiError::NotFound(format!("Pipeline run {} not found", id))
140→            }
141→            FactoryError::LockPoisoned => ApiError::Internal("Internal lock poisoned".to_string()),
142→            FactoryError::BadRequest(msg) => ApiError::BadRequest(msg),
143→            FactoryError::InvalidColumn { column, message } => {
144→                ApiError::BadRequest(format!("Invalid column '{}': {}", column, message))
145→            }
146→            FactoryError::PipelineAlreadyRunning { issue_id } => {
147→                ApiError::BadRequest(format!("Pipeline already running for issue {}", issue_id))
148→            }
149→            FactoryError::GitHub(msg) => ApiError::Internal(format!("GitHub API error: {}", msg)),
150→            FactoryError::Database(e) => ApiError::Internal(e.to_string()),
151→            FactoryError::Other(e) => ApiError::Internal(e.to_string()),
152→        }
153→    }
154→}
