249→/// Shared sync logic used by both the endpoint handler and auto-sync after clone.
250→async fn do_sync_github_issues(
251→    state: &SharedState,
252→    project_id: i64,
253→) -> Result<SyncResult, ApiError> {
254→    let github_repo = {
255→        let (existing_repo, project_path) = state
256→            .db
257→            .call(move |db| {
258→                let project = db
259→                    .get_project(project_id)?
260→                    .ok_or_else(|| anyhow::anyhow!("Project {} not found", project_id))?;
261→                Ok((project.github_repo.clone(), project.path.clone()))
262→            })
263→            .await
264→            .map_err(|e| {
265→                let msg = e.to_string();
266→                if msg.contains("not found") {
267→                    ApiError::from(FactoryError::ProjectNotFound { id: project_id })
268→                } else {
269→                    ApiError::Internal(msg)
270→                }
271→            })?;
272→
273→        match existing_repo {
274→            Some(repo) => repo,
275→            None => {
276→                // Try to detect github_repo from git remote (async to avoid blocking)
277→                let detected = detect_github_repo_from_path(&project_path).await;
278→                if let Some(ref owner_repo) = detected {
279→                    let owner_repo = owner_repo.clone();
280→                    let _ = state
281→                        .db
282→                        .call(move |db| db.update_project_github_repo(project_id, &owner_repo))
283→                        .await;
284→                }
285→                detected.ok_or_else(|| {
286→                    ApiError::BadRequest(
287→                        "Project has no GitHub repo configured and could not detect one from git remotes".into(),
288→                    )
289→                })?
290→            }
291→        }
292→    };
293→
294→    let token = state
295→        .github_token
296→        .lock()
297→        .map_err(|_| ApiError::from(FactoryError::LockPoisoned))?
298→        .clone()
299→        .ok_or_else(|| ApiError::BadRequest("Not connected to GitHub".into()))?;
300→
301→    let gh_issues = super::github::list_issues(&token, &github_repo)
302→        .await
303→        .map_err(|e| ApiError::Internal(format!("Failed to fetch GitHub issues: {}", e)))?;
304→
305→    let total_github = gh_issues.len();
306→    let mut imported = 0usize;
307→    let mut skipped = 0usize;
308→
309→    {
310→        // Collect data needed for DB closure (must be owned)
311→        let gh_data: Vec<(String, String, i64)> = gh_issues
312→            .iter()
313→            .map(|gh| {
314→                (
315→                    gh.title.clone(),
316→                    gh.body.clone().unwrap_or_default(),
317→                    gh.number,
318→                )
319→            })
320→            .collect();
321→
322→        let results = state
323→            .db
324→            .call(move |db| {
325→                let mut created = Vec::new();
326→                for (title, body, number) in &gh_data {
327→                    let result = db.create_issue_from_github(project_id, title, body, *number)?;
328→                    created.push(result);
329→                }
330→                Ok(created)
331→            })
332→            .await
333→            .map_err(|e| ApiError::Internal(e.to_string()))?;
334→
335→        for result in results {
336→            match result {
337→                Some(issue) => {
338→                    broadcast_message(&state.ws_tx, &WsMessage::IssueCreated { issue });
339→                    imported += 1;
340→                }
341→                None => {
342→                    skipped += 1;
343→                }
344→            }
345→        }
346→    }
347→
348→    Ok(SyncResult {
349→        imported,
350→        skipped,
351→        total_github,
352→    })
353→}
354→
355→/// Try to detect "owner/repo" from git remote URLs in a local repo path.
356→async fn detect_github_repo_from_path(path: &str) -> Option<String> {
357→    let output = tokio::process::Command::new("git")
358→        .args(["-C", path, "remote", "get-url", "origin"])
359→        .output()
360→        .await
361→        .ok()?;
362→    if !output.status.success() {
363→        return None;
364→    }
365→    let url = String::from_utf8_lossy(&output.stdout).trim().to_string();
366→    parse_github_owner_repo(&url)
367→}
