371→/// `GET /api/cli-help` — return parsed CLI help (commands and options).
372→///
373→/// Runs `forge --help` once, caches the result, and returns it as JSON.
374→async fn cli_help_handler() -> Result<Json<CliHelpResponse>, ApiError> {
375→    static CACHED: OnceLock<Result<CliHelpResponse, String>> = OnceLock::new();
376→
377→    let result = CACHED.get_or_init(|| {
378→        let forge_cmd = std::env::var("FORGE_CMD").unwrap_or_else(|_| "forge".to_string());
379→        let output = std::process::Command::new(&forge_cmd)
380→            .arg("--help")
381→            .output()
382→            .map_err(|e| format!("Failed to run {}: {}", forge_cmd, e))?;
383→
384→        let stdout = String::from_utf8_lossy(&output.stdout);
385→        Ok(parse_cli_help(&stdout))
386→    });
387→
388→    match result {
389→        Ok(resp) => Ok(Json(resp.clone())),
390→        Err(msg) => Err(ApiError::Internal(msg.clone())),
391→    }
392→}
