394→fn parse_cli_help(text: &str) -> CliHelpResponse {
395→    let mut commands = Vec::new();
396→    let mut options = Vec::new();
397→
398→    #[derive(PartialEq)]
399→    enum Section {

400→        None,
401→        Commands,
402→        Options,
403→    }
404→    let mut section = Section::None;
405→
406→    for line in text.lines() {
407→        let trimmed = line.trim_end();
408→        if trimmed == "Commands:" {
409→            section = Section::Commands;
410→            continue;
411→        } else if trimmed == "Options:" {
412→            section = Section::Options;
413→            continue;
414→        } else if !trimmed.is_empty() && !trimmed.starts_with(' ') {
415→            // A non-indented line that isn't a section header ends the current section
416→            section = Section::None;
417→            continue;
418→        }
419→
420→        let trimmed = trimmed.trim();
421→        if trimmed.is_empty() {
422→            continue;
423→        }
424→
425→        match section {
426→            Section::Commands => {
427→                // Format: "  name       Description text"
428→                let mut parts = trimmed.splitn(2, char::is_whitespace);
429→                let name = parts.next().unwrap_or("").to_string();
430→                let description = parts
431→                    .next()
432→                    .unwrap_or("")
433→                    .trim()
434→                    .to_string();
435→                if !name.is_empty() {
436→                    commands.push(CliCommand { name, description });
437→                }
438→            }
439→            Section::Options => {
440→                // Flag lines start with '-' (e.g. "-v, --verbose" or "--yes")
441→                if trimmed.starts_with('-') {
442→                    // Split on multiple spaces to separate flag from description
443→                    let flag;
444→                    let description;
445→                    // Some flags have <PLACEHOLDER> args, treat everything up to double-space as flag
446→                    if let Some(pos) = trimmed.find("  ") {
447→                        flag = trimmed[..pos].trim().to_string();
448→                        description = trimmed[pos..].trim().to_string();
449→                    } else {
450→                        flag = trimmed.to_string();
451→                        description = String::new();
452→                    }
453→                    options.push(CliOption { flag, description });
454→                } else if !options.is_empty() {
455→                    // Continuation line: append to the last option's description
456→                    let last = options.last_mut().unwrap();
457→                    if last.description.is_empty() {
458→                        last.description = trimmed.to_string();
459→                    } else {
460→                        last.description.push(' ');
461→                        last.description.push_str(trimmed);
462→                    }
463→                }
464→            }
465→            Section::None => {}
466→        }
467→    }
468→
469→    CliHelpResponse { commands, options }
470→}
