522→/// `POST /api/projects/clone` — clone a GitHub repository and register it.
523→///
524→/// Accepts a GitHub URL, shorthand (`owner/repo`), HTTPS URL, or SSH URL.
525→/// If a GitHub token is connected, it is injected for authentication.
526→///
527→/// **Request body:**
528→/// ```json
529→/// { "repo_url": "https://github.com/owner/repo" }
530→/// ```
531→///
532→/// **Response:** `201 Created` with the created `Project` as JSON.
533→///
534→/// **Errors:**
535→/// - `400 Bad Request` if the URL is unparseable or `git clone` fails
536→/// - `500 Internal Server Error` on filesystem or DB errors
537→async fn clone_project(
538→    State(state): State<SharedState>,
539→    Json(req): Json<CloneProjectRequest>,
540→) -> Result<impl IntoResponse, ApiError> {
541→    let repo_url = req.repo_url.trim().to_string();
542→
543→    // Parse repo name from URL (handles https://github.com/user/repo, user/repo, etc.)
544→    let repo_name = repo_url
545→        .trim_end_matches('/')
546→        .trim_end_matches(".git")
547→        .rsplit('/')
548→        .next()
549→        .ok_or_else(|| ApiError::BadRequest("Invalid repository URL".to_string()))?
550→        .to_string();
551→
552→    if repo_name.is_empty() {
553→        return Err(ApiError::BadRequest(
554→            "Could not parse repository name from URL".to_string(),
555→        ));
556→    }
557→
558→    // Normalize: if it looks like "user/repo", prepend GitHub URL
559→    let clone_url = if repo_url.starts_with("http://")
560→        || repo_url.starts_with("https://")
561→        || repo_url.starts_with("git@")
562→    {
563→        repo_url.clone()
564→    } else {
565→        format!("https://github.com/{}", repo_url)
566→    };
567→
568→    // If we have a GitHub token, use it for cloning (enables private repos)
569→    let (clone_url, token) = {
570→        let gh_token = state
571→            .github_token
572→            .lock()
573→            .map_err(|_| ApiError::from(FactoryError::LockPoisoned))?;
574→        if let Some(ref t) = *gh_token {
575→            if clone_url.starts_with("https://github.com/") {
576→                (
577→                    clone_url.replacen(
578→                        "https://github.com/",
579→                        &format!("https://x-access-token:{}@github.com/", t),
580→                        1,
581→                    ),
582→                    Some(t.clone()),
583→                )
584→            } else {
585→                (clone_url, Some(t.clone()))
586→            }
587→        } else {
588→            (clone_url, None)
589→        }
590→    };
591→
592→    // Clone into .forge/repos/<repo_name>
593→    let repos_dir = std::path::PathBuf::from(".forge/repos");
594→    tokio::fs::create_dir_all(&repos_dir)
595→        .await
596→        .map_err(|e| ApiError::Internal(format!("Failed to create repos directory: {}", e)))?;
597→
598→    let clone_path = repos_dir.join(&repo_name);
599→    let already_cloned = clone_path.exists();

600→
601→    if !already_cloned {
602→        let clone_path_str = clone_path.to_string_lossy().to_string();
603→
604→        // Run git clone asynchronously
605→        let output = tokio::process::Command::new("git")
606→            .args(["clone", &clone_url, &clone_path_str])
607→            .output()
608→            .await
609→            .map_err(|e| ApiError::Internal(format!("Failed to run git clone: {}", e)))?;
610→
611→        if !output.status.success() {
612→            let stderr = String::from_utf8_lossy(&output.stderr);
613→            let sanitized_stderr = if let Some(ref t) = token {
614→                stderr.trim().replace(t, "***")
615→            } else {
616→                stderr.trim().to_string()
617→            };
618→            return Err(ApiError::BadRequest(format!(
619→                "git clone failed: {}",
620→                sanitized_stderr
621→            )));
622→        }
623→
624→        // After successful clone, strip token from remote URL to prevent leaking
625→        if token.is_some() {
626→            let _ = tokio::process::Command::new("git")
627→                .args(["remote", "set-url", "origin", &repo_url])
628→                .current_dir(&clone_path_str)
629→                .output()
630→                .await;
631→        }
632→    }
633→
634→    // Resolve to absolute path for the project record
635→    let abs_path = tokio::fs::canonicalize(&clone_path)
636→        .await
637→        .map_err(|e| ApiError::Internal(format!("Failed to resolve path: {}", e)))?;
638→    let abs_path_str = abs_path.to_string_lossy().to_string();
639→
640→    // Parse the GitHub owner/repo from the original URL (before token injection)
641→    let github_repo = parse_github_owner_repo(&repo_url);
642→
643→    let repo_name_clone = repo_name.clone();
644→    let abs_path_clone = abs_path_str.clone();
645→    let github_repo_clone = github_repo.clone();
646→    let project = state
647→        .db
648→        .call(move |db| {
649→            // Check if a project already exists for this path
650→            let existing = db
651→                .list_projects()?
652→                .into_iter()
653→                .find(|p| p.path == abs_path_clone);
654→
655→            let project = if let Some(project) = existing {
656→                project
657→            } else {
658→                db.create_project(&repo_name_clone, &abs_path_clone)?
659→            };
660→
661→            // Store the GitHub owner/repo
662→            let project = if let Some(ref owner_repo) = github_repo_clone {
663→                db.update_project_github_repo(project.id, owner_repo)?
664→            } else {
665→                project
666→            };
667→            Ok(project)
668→        })
669→        .await
670→        .map_err(|e| ApiError::Internal(e.to_string()))?;
671→
672→    broadcast_message(
673→        &state.ws_tx,
674→        &WsMessage::ProjectCreated {
675→            project: project.clone(),
676→        },
677→    );
678→
679→    // Auto-sync GitHub issues in the background
680→    if github_repo.is_some() {
681→        let state_clone = Arc::clone(&state);
682→        let pid = project.id;
683→        tokio::spawn(async move {
684→            tokio::time::sleep(std::time::Duration::from_millis(500)).await;
685→            match do_sync_github_issues(&state_clone, pid).await {
686→                Ok(result) => {
687→                    eprintln!(
688→                        "Auto-synced {} GitHub issues for project {}",
689→                        result.imported, pid
690→                    );
691→                }
692→                Err(_) => {
693→                    eprintln!("Auto-sync GitHub issues failed for project {}", pid);
694→                }
695→            }
696→        });
697→    }
698→
699→    Ok((StatusCode::CREATED, Json(project)))
700→}
