1205→/// `POST /api/github/device-code` — initiate the GitHub Device Authorization Flow.
1206→///
1207→/// Requires `GITHUB_CLIENT_ID` env var to be set at server startup.
1208→/// The client should display `verification_uri` + `user_code` to the user,
1209→/// then poll `POST /api/github/poll` every `interval` seconds.
1210→///
1211→/// **Errors:** `400 Bad Request` if `GITHUB_CLIENT_ID` is not configured.
1212→async fn github_device_code(
1213→    State(state): State<SharedState>,
1214→) -> Result<impl IntoResponse, ApiError> {
1215→    let client_id = state
1216→        .github_client_id
1217→        .as_deref()
1218→        .ok_or_else(|| ApiError::BadRequest("GITHUB_CLIENT_ID not configured".into()))?;
1219→    let resp = super::github::request_device_code(client_id)
1220→        .await
1221→        .map_err(|e| ApiError::Internal(e.to_string()))?;
1222→    Ok(Json(resp))
1223→}
