1225→/// `POST /api/github/poll` — poll for a GitHub device flow access token.
1226→///
1227→/// **Request body:**
1228→/// ```json
1229→/// { "device_code": "<code from device-code response>" }
1230→/// ```
1231→///
1232→/// **Response:** `200 OK` with `{ "status": "complete" }` when the token is available,
1233→/// or `{ "status": "pending" }` while the user has not yet authorized.
1234→///
1235→/// **Errors:** `400 Bad Request` if `GITHUB_CLIENT_ID` is not configured.
1236→async fn github_poll_token(
1237→    State(state): State<SharedState>,
1238→    Json(req): Json<PollTokenRequest>,
1239→) -> Result<impl IntoResponse, ApiError> {
1240→    let client_id = state
1241→        .github_client_id
1242→        .as_deref()
1243→        .ok_or_else(|| ApiError::BadRequest("GITHUB_CLIENT_ID not configured".into()))?;
1244→    match super::github::poll_for_token(client_id, &req.device_code)
1245→        .await
1246→        .map_err(|e| ApiError::Internal(e.to_string()))?
1247→    {
1248→        Some(token) => {
1249→            let mut gh_token = state
1250→                .github_token
1251→                .lock()
1252→                .map_err(|_| ApiError::from(FactoryError::LockPoisoned))?;
1253→            *gh_token = Some(token);
1254→            Ok(Json(serde_json::json!({"status": "complete"})))
1255→        }
1256→        None => Ok(Json(serde_json::json!({"status": "pending"}))),
1257→    }
1258→}
