1274→        .map_err(|_| ApiError::from(FactoryError::LockPoisoned))?
1275→        .clone()
1276→        .ok_or_else(|| ApiError::BadRequest("Not connected to GitHub".into()))?;
1277→    let repos = super::github::list_repos(&token, 1, 100)
1278→        .await
