1283→/// `POST /api/github/connect` — connect to GitHub using a Personal Access Token (PAT).
1284→///
1285→/// Validates the token by calling the GitHub API before storing it.
1286→///
1287→/// **Request body:**
1288→/// ```json
1289→/// { "token": "ghp_..." }
1290→/// ```
1291→///
1292→/// **Response:** `200 OK` with `{ "status": "connected" }`.
1293→///
1294→/// **Errors:**
1295→/// - `400 Bad Request` if the token is empty or fails GitHub validation
1296→async fn github_connect_token(
1297→    State(state): State<SharedState>,
1298→    Json(req): Json<ConnectTokenRequest>,
1299→) -> Result<impl IntoResponse, ApiError> {
1300→    let token = req.token.trim().to_string();
1301→    if token.is_empty() {
1302→        return Err(ApiError::BadRequest("Token is required".into()));
1303→    }
1304→    // Validate the token by attempting to list repos
1305→    super::github::list_repos(&token, 1, 1).await.map_err(|_| {
1306→        ApiError::BadRequest("Invalid token — could not authenticate with GitHub".into())
1307→    })?;
1308→    let token_for_db = token.clone();
1309→    {
1310→        let mut gh_token = state
1311→            .github_token
1312→            .lock()
1313→            .map_err(|_| ApiError::from(FactoryError::LockPoisoned))?;
1314→        *gh_token = Some(token);
1315→    }
1316→    // Persist token to DB settings
1317→    state
1318→        .db
1319→        .call(move |db| db.set_setting("github_token", &token_for_db))
1320→        .await
1321→        .map_err(|e| ApiError::Internal(format!("Failed to persist token: {}", e)))?;
1322→    Ok(Json(serde_json::json!({"status": "connected"})))
1323→}
1324→
1325→/// `POST /api/github/disconnect` — remove the stored GitHub token.
1326→///
1327→/// Clears the token from in-memory state and deletes it from the DB settings table.
1328→///
1329→/// **Response:** `200 OK` with `{ "status": "disconnected" }`.
1330→async fn github_disconnect(
1331→    State(state): State<SharedState>,
1332→) -> Result<impl IntoResponse, ApiError> {
1333→    {
1334→        let mut token = state
1335→            .github_token
1336→            .lock()
1337→            .map_err(|_| ApiError::from(FactoryError::LockPoisoned))?;
1338→        *token = None;
1339→    }
1340→    state
1341→        .db
1342→        .call(move |db| db.delete_setting("github_token"))
1343→        .await
1344→        .map_err(|e| ApiError::Internal(format!("Failed to delete token: {}", e)))?;
1345→    Ok(Json(serde_json::json!({"status": "disconnected"})))
1346→}
