1924→            github_token: Mutex::new(None),
1925→        });
1926→        let app = api_router().with_state(state);
1927→
1928→        // Subscribe to broadcasts before the action
1929→        let mut rx = ws_tx.subscribe();
1930→
1931→        // Create project first
1932→        let create_proj = Request::builder()
1933→            .method("POST")
1934→            .uri("/api/projects")
1935→            .header("content-type", "application/json")
