1938→            ))
1939→            .unwrap();
1940→        app.clone().oneshot(create_proj).await.unwrap();
1941→
1942→        // Drain the project_created message
1943→        let _ = rx.recv().await.unwrap();
1944→
1945→        // Create issue
1946→        let request = Request::builder()
1947→            .method("POST")
1948→            .uri("/api/projects/1/issues")
1949→            .header("content-type", "application/json")
1950→            .body(Body::from(
