1957→        assert_eq!(response.status(), StatusCode::CREATED);
1958→
1959→        // Verify the broadcast message was received in typed WsMessage format
1960→        let msg = rx.recv().await.unwrap();
1961→        let parsed: serde_json::Value = serde_json::from_str(&msg).unwrap();
1962→        assert_eq!(parsed["type"], "IssueCreated");
