100→/// Convert a title to a URL-safe slug, limited to `max_len` characters.
101→pub fn slugify(title: &str, max_len: usize) -> String {
102→    let slug: String = title
103→        .to_lowercase()
104→        .chars()
105→        .map(|c| if c.is_alphanumeric() { c } else { '-' })
106→        .collect::<String>()
107→        .split('-')
108→        .filter(|s| !s.is_empty())
109→        .collect::<Vec<_>>()
110→        .join("-");
111→    if slug.len() > max_len {
112→        slug[..slug.floor_char_boundary(max_len)]
113→            .trim_end_matches('-')
114→            .to_string()
115→    } else {
116→        slug
117→    }
118→}
