127→        .args(["checkout", "-b", &branch_name])
128→        .current_dir(project_path)
129→        .stdout(Stdio::null())
130→        .stderr(Stdio::piped())
131→        .output()
132→        .await
133→        .context("Failed to run git checkout -b")?;
134→
135→    if !output.status.success() {
136→        let stderr = String::from_utf8_lossy(&output.stderr);
137→
138→        // Branch already exists — switch to it instead
139→        if stderr.contains("already exists") {
140→            let switch = tokio::process::Command::new("git")
141→                .args(["checkout", &branch_name])
142→                .current_dir(project_path)
143→                .stdout(Stdio::null())
144→                .stderr(Stdio::piped())
145→                .output()
146→                .await
147→                .context("Failed to run git checkout")?;
148→
149→            if !switch.status.success() {
150→                let switch_stderr = String::from_utf8_lossy(&switch.stderr);
151→                anyhow::bail!(
152→                    "Failed to switch to existing branch {}: {}",
153→                    branch_name,
154→                    switch_stderr.trim()
155→                );
156→            }
157→        } else {
158→            anyhow::bail!("Failed to create branch {}: {}", branch_name, stderr.trim());
159→        }
160→    }
161→
162→    Ok(branch_name)
163→}
