2352→        // Create a script that:
2353→        // - Exits with error when called with -p (planner call uses `-p` flag) so it falls back fast
2354→        // - Sleeps for 60s otherwise (pipeline execution via `claude --print --output-format stream-json <prompt>`) so we can cancel it
2355→        let script_path = tmp_dir.path().join("forge_test_sleep_cancel.sh");
2356→        std::fs::write(
2357→            &script_path,
2358→            "#!/bin/sh\nfor arg in \"$@\"; do case \"$arg\" in -p) exit 1;; esac; done\nsleep 60\n",
2359→        )
2360→        .unwrap();
2361→        std::fs::set_permissions(&script_path, std::fs::Permissions::from_mode(0o755)).unwrap();
2362→
2363→        unsafe { std::env::set_var("CLAUDE_CMD", script_path.to_str().unwrap()) };
2364→
2365→        let db = FactoryDb::new_in_memory().unwrap();
2366→        let project = db.create_project("test", tmp_path).unwrap();
2367→        let issue = db
2368→            .create_issue(project.id, "Cancel test", "", &IssueColumn::Backlog)
2369→            .unwrap();
2370→        let run = db.create_pipeline_run(issue.id).unwrap();
2371→
2372→        let db = DbHandle::new(db);
2373→        let (tx, _rx) = broadcast::channel(16);
