2376→        runner
2377→            .start_run(run.id, &issue, db.clone(), tx.clone())
2378→            .await
2379→            .unwrap();
2380→
2381→        // Wait for the process to be registered in the running_processes map.
2382→        // We poll because the spawned task needs to actually call spawn() and insert.
2383→        // The planner step may take several seconds (tries Claude CLI, fails, falls back).
2384→        let mut tracked = false;
