1163→/// Auto-generate spec and phases from an issue description.
1164→/// Writes a design doc to `.forge/spec.md`, then runs `forge generate`.
1165→/// Returns Ok(true) if phases were generated successfully, Ok(false) if generation
1166→/// failed or produced no output (caller should fall back to direct invocation).
1167→async fn auto_generate_phases(
1168→    project_path: &str,
1169→    issue_title: &str,
1170→    issue_description: &str,
1171→) -> Result<bool> {
1172→    // Ensure .forge directory exists
1173→    let forge_dir = std::path::Path::new(project_path).join(".forge");
1174→    if !forge_dir.exists() {
1175→        tokio::fs::create_dir_all(&forge_dir)
1176→            .await
1177→            .context("Failed to create .forge directory")?;
1178→    }
1179→
1180→    // Write a design document from the issue
1181→    let design_content = format!(
1182→        "# {}\n\n## Overview\n\n{}\n\n## Requirements\n\n- Implement the feature described above\n- Ensure all existing tests continue to pass\n- Add tests for new functionality\n",
1183→        issue_title,
1184→        if issue_description.is_empty() {
1185→            "No additional details provided."
1186→        } else {
1187→            issue_description
1188→        }
1189→    );
1190→    let design_path = forge_dir.join("spec.md");
1191→    tokio::fs::write(&design_path, &design_content)
1192→        .await
1193→        .context("Failed to write design document")?;
1194→
1195→    // Run forge generate to create phases.json
1196→    let forge_cmd = std::env::var("FORGE_CMD").unwrap_or_else(|_| "forge".to_string());
1197→    let status = match tokio::process::Command::new(&forge_cmd)
1198→        .arg("generate")
1199→        .current_dir(project_path)
1200→        .stdout(Stdio::piped())
1201→        .stderr(Stdio::piped())
1202→        .status()
1203→        .await
1204→    {
1205→        Ok(s) => s,
1206→        Err(_) => return Ok(false),
1207→    };
1208→
1209→    if status.success() && has_forge_phases(project_path) {
1210→        Ok(true)
1211→    } else {
1212→        // Generation failed — fall back to simple Claude invocation
1213→        Ok(false)
1214→    }
1215→}
