1217→/// Build the command to execute: `forge swarm` if phases exist, otherwise `claude --print`.
1218→fn build_execution_command(
1219→    project_path: &str,
1220→    issue_title: &str,
1221→    issue_description: &str,
1222→) -> tokio::process::Command {
1223→    if has_forge_phases(project_path) {
1224→        // Use forge swarm for full DAG-based parallel execution
1225→        let forge_cmd = std::env::var("FORGE_CMD").unwrap_or_else(|_| "forge".to_string());
1226→        let mut cmd = tokio::process::Command::new(&forge_cmd);
1227→        cmd.arg("swarm")
1228→            .arg("--max-parallel")
1229→            .arg("4")
1230→            .arg("--fail-fast")
1231→            .env_remove("CLAUDECODE")
1232→            .current_dir(project_path)
1233→            .stdout(Stdio::piped())
1234→            .stderr(Stdio::piped());
1235→        cmd
1236→    } else {
1237→        // Fallback: direct Claude invocation for simple issues without phases
1238→        // Uses stream-json output format for realtime output streaming to the UI
1239→        let claude_cmd = std::env::var("CLAUDE_CMD").unwrap_or_else(|_| "claude".to_string());
1240→        let prompt = format!(
1241→            "Implement the following issue:\n\nTitle: {}\n\nDescription: {}\n",
1242→            issue_title, issue_description
1243→        );
1244→        let mut cmd = tokio::process::Command::new(&claude_cmd);
1245→        cmd.arg("--print")
1246→            .arg("--verbose")
1247→            .arg("--output-format")
1248→            .arg("stream-json")
1249→            .arg("--dangerously-skip-permissions")
1250→            .arg(&prompt)
1251→            .env_remove("CLAUDECODE")
1252→            .current_dir(project_path)
1253→            .stdout(Stdio::piped())
1254→            .stderr(Stdio::piped());
1255→        cmd
1256→    }
1257→}
