249→impl PipelineRunner {
250→    pub fn new(project_path: &str, sandbox: Option<Arc<DockerSandbox>>) -> Self {
251→        Self {
252→            project_path: project_path.to_string(),
253→            running_processes: Arc::new(tokio::sync::Mutex::new(HashMap::new())),
254→            sandbox,
