258→
259→    /// Cancel a running pipeline by killing its child process and updating the DB.
260→    /// Returns the updated PipelineRun or an error if the run doesn't exist or DB update fails.
261→    pub async fn cancel(
262→        &self,
263→        run_id: i64,
264→        db: &DbHandle,
265→        tx: &broadcast::Sender<String>,
266→    ) -> Result<PipelineRun> {
267→        // Kill the child process or stop the container if it exists
268→        {
269→            let mut processes = self.running_processes.lock().await;
270→            if let Some(handle) = processes.remove(&run_id) {
271→                match handle {
272→                    RunHandle::Process(mut child) => {
273→                        if let Err(e) = child.kill().await {
274→                            eprintln!(
275→                                "[factory] WARNING: failed to kill process for run {}: {}",
276→                                run_id, e
277→                            );
278→                        }
279→                    }
280→                    RunHandle::Container(container_id) => {
281→                        if let Some(ref sandbox) = self.sandbox
282→                            && let Err(e) = sandbox.stop(&container_id).await
283→                        {
284→                            eprintln!(
285→                                "[factory] WARNING: failed to stop container {} for run {}: {}",
286→                                container_id, run_id, e
287→                            );
288→                        }
289→                    }
290→                }
291→            }
292→        }
