336→    /// Stop all active pipeline containers/processes on shutdown.
337→    pub async fn shutdown(&self) {
338→        let mut processes = self.running_processes.lock().await;
339→        for (run_id, handle) in processes.drain() {
340→            eprintln!("[factory] Shutting down pipeline run {}", run_id);
341→            match handle {
342→                RunHandle::Process(mut child) => {
343→                    if let Err(e) = child.kill().await {
344→                        eprintln!(
345→                            "[factory] WARNING: failed to kill process for run {}: {}",
346→                            run_id, e
347→                        );
348→                    }
349→                }
350→                RunHandle::Container(container_id) => {
351→                    if let Some(ref sandbox) = self.sandbox
352→                        && let Err(e) = sandbox.stop(&container_id).await
353→                    {
354→                        eprintln!(
355→                            "[factory] WARNING: failed to stop container {} for run {}: {}",
356→                            container_id, run_id, e
357→                        );
358→                    }
359→                }
360→            }
361→        }
362→    }
