 423→            return Ok(PlanOutcome::FallbackToForge);
 424→        }
 425→
 426→        // Step 2: Create team + tasks in DB
 427→        // Parse strategy/isolation/roles outside the closure (they use &str references from plan)
 428→        let strategy: ExecutionStrategy = plan
 429→            .strategy
 430→            .parse()
 431→            .map_err(|_| anyhow::anyhow!("Invalid strategy from planner: '{}'", plan.strategy))?;
 432→        let isolation: IsolationStrategy = plan
 433→            .isolation
 434→            .parse()
 435→            .map_err(|_| anyhow::anyhow!("Invalid isolation from planner: '{}'", plan.isolation))?;
 436→        let mut parsed_tasks: Vec<(String, String, AgentRole, i32, Vec<i32>, IsolationStrategy)> =
 437→            Vec::new();
 438→        for plan_task in &plan.tasks {
 439→            let role: AgentRole = plan_task
 440→                .role
 441→                .parse()
 442→                .map_err(|_| anyhow::anyhow!("Invalid role from planner: '{}'", plan_task.role))?;
 443→            let task_isolation: IsolationStrategy = plan_task.isolation.parse().map_err(|_| {
 444→                anyhow::anyhow!("Invalid isolation from planner: '{}'", plan_task.isolation)
 445→            })?;
 446→            parsed_tasks.push((
 447→                plan_task.name.clone(),
 448→                plan_task.description.clone(),
 449→                role,
 450→                plan_task.wave,
 451→                plan_task.depends_on.clone(),
 452→                task_isolation,
 453→            ));
 454→        }
 455→        let reasoning = plan.reasoning.clone();
 456→        let (team, db_tasks) = db
 457→            .call(move |db| {
 458→                let team = db.create_agent_team(run_id, &strategy, &isolation, &reasoning)?;
 459→
 460→                let mut db_tasks = Vec::new();
 461→                for (name, description, role, wave, depends_on, task_isolation) in &parsed_tasks {
 462→                    let depends: Vec<i64> = depends_on
 463→                        .iter()
 464→                        .filter_map(|&idx| db_tasks.get(idx as usize).map(|t: &AgentTask| t.id))
 465→                        .collect();
 466→                    let task = db.create_agent_task(
 467→                        team.id,
 468→                        name,
 469→                        description,
 470→                        role,
 471→                        *wave,
 472→                        &depends,
 473→                        task_isolation,
 474→                    )?;
 475→                    db_tasks.push(task);
 476→                }
 477→                Ok((team, db_tasks))
 478→            })
 479→            .await?;
 480→
 481→        // Step 3: Broadcast TeamCreated
 482→        broadcast_message(
 483→            tx,
 484→            &WsMessage::TeamCreated {
 485→                run_id,
 486→                team_id: team.id,
 487→                strategy: team.strategy.clone(),
 488→                isolation: team.isolation.clone(),
 489→                plan_summary: plan.reasoning.clone(),
 490→                tasks: db_tasks.clone(),
 491→            },
 492→        );
 493→
 494→        // Step 4: Execute wave by wave
 495→        let executor = Arc::clone(task_runner);
 496→        let max_wave = plan.max_wave();
 497→        let base_branch = branch_name.as_deref().unwrap_or("main");
 498→
 499→        for wave in 0..=max_wave {
 500→            let wave_tasks: Vec<&AgentTask> = db_tasks.iter().filter(|t| t.wave == wave).collect();
 501→
 502→            if wave_tasks.is_empty() {
 503→                continue;
 504→            }
 505→
 506→            let task_ids: Vec<i64> = wave_tasks.iter().map(|t| t.id).collect();
 507→            broadcast_message(
 508→                tx,
 509→                &WsMessage::WaveStarted {
 510→                    run_id,
 511→                    team_id: team.id,
 512→                    wave,
 513→                    task_ids: task_ids.clone(),
 514→                },
 515→            );
 516→
 517→            // Set up worktrees for tasks that need isolation
 518→            let mut task_working_dirs: Vec<(AgentTask, std::path::PathBuf, Option<String>)> =
 519→                Vec::new();
 520→            for task in &wave_tasks {
 521→                let (working_dir, task_branch) = if task.isolation_type
 522→                    == IsolationStrategy::Worktree
 523→                {
 524→                    match executor.setup_worktree(run_id, task, base_branch).await {
 525→                        Ok((path, branch)) => (path, Some(branch)),
 526→                        Err(e) => {
 527→                            if wave_tasks.len() > 1 {
 528→                                // Multiple parallel tasks need isolation; falling back to shared
 529→                                // directory would cause conflicts.
 530→                                anyhow::bail!(
 531→                                    "Worktree setup failed for task {} ({}) in parallel wave \
 532→                                     (wave has {} tasks, shared directory fallback is unsafe): {:#}",
 533→                                    task.id,
 534→                                    task.name,
 535→                                    wave_tasks.len(),
 536→                                    e
 537→                                );
 538→                            }
 539→                            eprintln!(
 540→                                "[pipeline] run_id={}: worktree setup failed for task {} ({}): {:#}. \
 541→                                 Falling back to shared directory (single-task wave).",
 542→                                run_id, task.id, task.name, e
 543→                            );
 544→                            broadcast_message(
 545→                                tx,
 546→                                &WsMessage::AgentSignal {
 547→                                    run_id,
 548→                                    task_id: task.id,
 549→                                    signal_type: SignalType::Blocker,
 550→                                    content: format!(
 551→                                        "Worktree isolation failed, running in shared directory: {}",
 552→                                        e
 553→                                    ),
 554→                                },
 555→                            );
 556→                            (std::path::PathBuf::from(project_path), None)
 557→                        }
 558→                    }
 559→                } else {
 560→                    (std::path::PathBuf::from(project_path), None)
 561→                };
 562→                task_working_dirs.push(((*task).clone(), working_dir, task_branch));
 563→            }
 564→
 565→            // Run tasks in parallel
 566→            let mut handles = Vec::new();
 567→            for (task, working_dir, _branch) in &task_working_dirs {
 568→                let executor_ref = Arc::clone(task_runner);
 569→                let task_clone = task.clone();
 570→                let dir_clone = working_dir.clone();
 571→                let run_id_clone = run_id;
 572→                let use_team = wave_tasks.len() > 1;
 573→                let worktree_path = if task.isolation_type == IsolationStrategy::Worktree {
 574→                    Some(working_dir.clone())
 575→                } else {
 576→                    None
 577→                };
 578→
 579→                let handle = tokio::spawn(async move {
 580→                    executor_ref
 581→                        .run_task(
 582→                            run_id_clone,
 583→                            &task_clone,
 584→                            use_team,
 585→                            &dir_clone,
 586→                            worktree_path,
 587→                        )
 588→                        .await
 589→                });
 590→                handles.push(handle);
 591→            }
 592→
 593→            // Wait for all tasks in this wave
 594→            let mut success_count: u32 = 0;
 595→            let mut failed_count: u32 = 0;
 596→            for handle in handles {
 597→                match handle.await {
 598→                    Ok(Ok(true)) => success_count += 1,
 599→                    Ok(Ok(false)) => {
 600→                        // Task completed but reported failure (DB already updated by run_task)
 601→                        failed_count += 1;
 602→                    }
 603→                    Ok(Err(e)) => {
 604→                        eprintln!(
 605→                            "[pipeline] run_id={}: task execution error: {:#}",
 606→                            run_id, e
 607→                        );
 608→                        failed_count += 1;
 609→                    }
 610→                    Err(join_err) => {
 611→                        eprintln!("[pipeline] run_id={}: task panicked: {}", run_id, join_err);
 612→                        failed_count += 1;
 613→                    }
 614→                }
 615→            }
 616→
 617→            // Collect worktree paths for cleanup (before merge loop, so we clean all even on conflict)
 618→            let worktree_paths: Vec<_> = task_working_dirs
 619→                .iter()
 620→                .filter(|(task, _, _)| task.isolation_type == IsolationStrategy::Worktree)
 621→                .map(|(_, dir, _)| dir.clone())
 622→                .collect();
 623→
 624→            // Merge branches from worktrees (under project lock)
 625→            if wave_tasks.len() > 1 || task_working_dirs.iter().any(|(_, _, b)| b.is_some()) {
 626→                let git_lock = git_locks.get(project_path).await;
 627→                let _guard = git_lock.lock().await;
 628→
 629→                broadcast_message(tx, &WsMessage::MergeStarted { run_id, wave });
 630→
 631→                let mut merge_conflicts = false;
 632→                for (_task, _working_dir, task_branch) in &task_working_dirs {
 633→                    if let Some(branch) = task_branch {
 634→                        let merged = executor.merge_branch(branch, base_branch).await;
 635→                        match merged {
 636→                            Ok(true) => { /* success */ }
 637→                            Ok(false) => {
 638→                                eprintln!(
 639→                                    "[pipeline] run_id={}: merge conflict for branch {}",
 640→                                    run_id, branch
 641→                                );
 642→                                merge_conflicts = true;
 643→                                break;
 644→                            }
 645→                            Err(e) => {
 646→                                eprintln!(
 647→                                    "[pipeline] run_id={}: merge command failed for branch {}: {:#}",
 648→                                    run_id, branch, e
 649→                                );
 650→                                merge_conflicts = true;
 651→                                break;
 652→                            }
 653→                        }
 654→                    }
 655→                }
 656→
 657→                broadcast_message(
 658→                    tx,
 659→                    &WsMessage::MergeCompleted {
 660→                        run_id,
 661→                        wave,
 662→                        conflicts: merge_conflicts,
 663→                    },
 664→                );
 665→                // git lock released at end of block
 666→            }
 667→
 668→            // Always clean up ALL worktrees, even after merge conflict
 669→            for dir in &worktree_paths {
 670→                if let Err(e) = executor.cleanup_worktree(dir).await {
 671→                    eprintln!(
 672→                        "[pipeline] Failed to clean up worktree {}: {:#}",
 673→                        dir.display(),
 674→                        e
 675→                    );
 676→                }
 677→            }
 678→
 679→            broadcast_message(
 680→                tx,
 681→                &WsMessage::WaveCompleted {
 682→                    run_id,
 683→                    team_id: team.id,
 684→                    wave,
 685→                    success_count,
 686→                    failed_count,
 687→                },
 688→            );
 689→
 690→            // If any task failed, abort
 691→            if failed_count > 0 {
 692→                anyhow::bail!("Wave {} had {} failed tasks", wave, failed_count);
 693→            }
 694→        }
 695→
 696→        Ok(PlanOutcome::TeamExecuted(format!(
 697→            "Agent team completed: {} tasks across {} waves",
 698→            db_tasks.len(),
 699→            max_wave + 1
 700→        )))
 701→    }
