 703→    /// Fallback to forge pipeline execution (auto-generate phases, then run Docker or local).
 704→    #[allow(clippy::too_many_arguments)]
 705→    async fn run_forge_fallback(
 706→        run_id: i64,
 707→        project_path: &str,
 708→        issue_title: &str,
 709→        issue_description: &str,
 710→        sandbox_clone: &Option<Arc<DockerSandbox>>,
 711→        running_processes: &Arc<tokio::sync::Mutex<HashMap<i64, RunHandle>>>,
 712→        db: &DbHandle,
 713→        tx: &broadcast::Sender<String>,
 714→    ) -> Result<String> {
 715→        // Auto-generate phases if none exist
 716→        if !has_forge_phases(project_path)
 717→            && is_forge_initialized(project_path)
 718→            && let Err(e) = auto_generate_phases(project_path, issue_title, issue_description).await
 719→        {
 720→            broadcast_message(
 721→                tx,
 722→                &WsMessage::PipelineError {
 723→                    run_id,
 724→                    message: format!("Failed to auto-generate phases: {:#}", e),
 725→                },
 726→            );
 727→        }
 728→
 729→        // Execute the pipeline (Docker or Local)
 730→        if let Some(sandbox) = sandbox_clone {
 731→            let timeout = match SandboxConfig::load(std::path::Path::new(project_path)) {
 732→                Ok(config) => config.timeout,
 733→                Err(e) => {
 734→                    eprintln!(
 735→                        "[pipeline] run_id={}: Failed to load sandbox config, using default timeout (1800s): {:#}",
 736→                        run_id, e
 737→                    );
 738→                    1800
 739→                }
 740→            };
 741→            execute_pipeline_docker(
 742→                run_id,
 743→                project_path,
 744→                issue_title,
 745→                issue_description,
 746→                sandbox,
 747→                running_processes,
 748→                db,
 749→                tx,
 750→                timeout,
 751→            )
 752→            .await
 753→        } else {
 754→            execute_pipeline_streaming(
 755→                run_id,
 756→                project_path,
 757→                issue_title,
 758→                issue_description,
 759→                running_processes,
 760→                db,
 761→                tx,
 762→            )
 763→            .await
 764→        }
 765→    }
