 767→    /// Start a pipeline run for the given issue. Creates a git branch, attempts agent team
 768→    /// execution (planner -> parallel tasks), falls back to forge pipeline on failure,
 769→    /// and creates a PR on success.
 770→    pub async fn start_run(
 771→        &self,
 772→        run_id: i64,
 773→        issue: &Issue,
 774→        db: DbHandle,
 775→        tx: broadcast::Sender<String>,
 776→    ) -> Result<()> {
 777→        // Look up the project path from the DB (per-project, not the global default)
 778→        let project_id = issue.project_id;
 779→        let project_path = db
 780→            .call(move |db| match db.get_project(project_id) {
 781→                Ok(Some(project)) => Ok(project.path),
 782→                Ok(None) => {
 783→                    anyhow::bail!("Project {} not found in DB", project_id);
 784→                }
 785→                Err(e) => Err(e.context(format!("Failed to look up project {}", project_id))),
 786→            })
 787→            .await?;
 788→        let project_path = translate_host_path_to_container(&project_path);
 789→        let issue_id = issue.id;
 790→        let issue_title = issue.title.clone();
 791→        let issue_description = issue.description.clone();
 792→        let issue_labels = issue.labels.clone();
 793→        let running_processes = Arc::clone(&self.running_processes);
 794→        let sandbox_clone = self.sandbox.clone();
 795→        let git_locks = self.git_locks.clone();
 796→
 797→        let from_column = issue.column.as_str().to_string();
 798→
 799→        // Update status to Running and move issue to InProgress
 800→        {
 801→            let need_move = issue.column != IssueColumn::InProgress;
 802→            let run = db
 803→                .call(move |db| {
 804→                    let run =
 805→                        db.update_pipeline_run(run_id, &PipelineStatus::Running, None, None)?;
 806→                    if need_move
 807→                        && let Err(e) = db.move_issue(issue_id, &IssueColumn::InProgress, 0)
 808→                    {
 809→                        eprintln!(
 810→                            "[pipeline] run_id={}: failed to move issue to InProgress: {:#}",
 811→                            run_id, e
 812→                        );
 813→                    }
 814→                    Ok(run)
 815→                })
 816→                .await?;
 817→            broadcast_message(&tx, &WsMessage::PipelineStarted { run });
 818→            if issue.column != IssueColumn::InProgress {
 819→                broadcast_message(
 820→                    &tx,
 821→                    &WsMessage::IssueMoved {
 822→                        issue_id,
 823→                        from_column: from_column.clone(),
 824→                        to_column: "in_progress".to_string(),
 825→                        position: 0,
 826→                    },
 827→                );
 828→            }
 829→        }
 830→
 831→        // Spawn background task for execution
 832→        tokio::spawn(async move {
 833→            // Step 1: Create a git branch for isolation (under project lock)
 834→            let branch_name = {
 835→                let git_result = {
 836→                    let git_lock = git_locks.get(&project_path).await;
 837→                    let _guard = git_lock.lock().await;
 838→                    create_git_branch(&project_path, issue_id, &issue_title).await
 839→                };
 840→                // git lock released — now safe to acquire DB lock
 841→                match git_result {
 842→                    Ok(name) => {
 843→                        // Store branch name in DB and broadcast
 844→                        {
 845→                            let name_clone = name.clone();
 846→                            if let Err(e) = db
 847→                                .call(move |db| db.update_pipeline_branch(run_id, &name_clone))
 848→                                .await
 849→                            {
 850→                                eprintln!(
 851→                                    "[pipeline] run_id={}: failed to update pipeline branch: {:#}",
 852→                                    run_id, e
 853→                                );
 854→                            }
 855→                        }
 856→                        broadcast_message(
 857→                            &tx,
 858→                            &WsMessage::PipelineBranchCreated {
 859→                                run_id,
 860→                                branch_name: name.clone(),
 861→                            },
 862→                        );
 863→                        Some(name)
 864→                    }
 865→                    Err(e) => {
 866→                        eprintln!(
 867→                            "[pipeline] run_id={}: failed to create git branch: {:#}. Continuing without branch isolation.",
 868→                            run_id, e
 869→                        );
 870→                        broadcast_message(
 871→                            &tx,
 872→                            &WsMessage::AgentSignal {
 873→                                run_id,
 874→                                task_id: 0,
 875→                                signal_type: SignalType::Blocker,
 876→                                content: format!(
 877→                                    "[pipeline] Git branch creation failed, continuing without branch isolation: {}",
 878→                                    e
 879→                                ),
 880→                            },
 881→                        );
 882→                        None
 883→                    }
 884→                }
 885→            };
 886→
 887→            // Construct real planner and task runner for the agent team
 888→            eprintln!(
 889→                "[pipeline] run_id={}: starting planner for project at {}",
 890→                run_id, project_path
 891→            );
 892→            broadcast_message(
 893→                &tx,
 894→                &WsMessage::PipelineOutput {
 895→                    run_id,
 896→                    content: "Analyzing codebase and planning tasks...".to_string(),
 897→                },
 898→            );
 899→            let planner = Planner::new(&project_path);
 900→            let task_runner: Arc<dyn TaskRunner> =
 901→                Arc::new(AgentExecutor::new(&project_path, db.clone(), tx.clone()));
 902→
 903→            // Step 2: Try agent team pipeline first, fall back to forge pipeline
 904→            let team_result = Self::execute_agent_team(
 905→                &project_path,
 906→                run_id,
 907→                &issue_title,
 908→                &issue_description,
 909→                &issue_labels,
 910→                &branch_name,
 911→                &db,
 912→                &tx,
 913→                &git_locks,
 914→                &planner,
 915→                &task_runner,
 916→            )
 917→            .await;
 918→
 919→            eprintln!(
 920→                "[pipeline] run_id={}: planner returned: {}",
 921→                run_id,
 922→                match &team_result {
 923→                    Ok(PlanOutcome::TeamExecuted(_)) => "TeamExecuted".to_string(),
 924→                    Ok(PlanOutcome::FallbackToForge) => "FallbackToForge".to_string(),
 925→                    Err(e) => format!("Error: {:#}", e),
 926→                }
 927→            );
 928→            let result = match team_result {
 929→                Ok(PlanOutcome::TeamExecuted(summary)) => {
 930→                    // Team succeeded, use summary
 931→                    Ok(summary)
 932→                }
 933→                Ok(PlanOutcome::FallbackToForge) => {
 934→                    eprintln!(
 935→                        "[pipeline] run_id={}: single-task plan, using forge pipeline",
 936→                        run_id
 937→                    );
 938→                    broadcast_message(
 939→                        &tx,
 940→                        &WsMessage::PipelineOutput {
 941→                            run_id,
 942→                            content: "Running single-task pipeline...".to_string(),
 943→                        },
 944→                    );
 945→                    // Expected fallback -- continue to forge pipeline below
 946→                    Self::run_forge_fallback(
 947→                        run_id,
 948→                        &project_path,
 949→                        &issue_title,
 950→                        &issue_description,
 951→                        &sandbox_clone,
 952→                        &running_processes,
 953→                        &db,
 954→                        &tx,
 955→                    )
 956→                    .await
 957→                }
 958→                Err(e) => {
 959→                    eprintln!(
 960→                        "[pipeline] run_id={}: agent team failed unexpectedly: {:#}",
 961→                        run_id, e
 962→                    );
 963→                    broadcast_message(
 964→                        &tx,
 965→                        &WsMessage::AgentSignal {
 966→                            run_id,
 967→                            task_id: 0,
 968→                            signal_type: SignalType::Blocker,
 969→                            content: format!(
 970→                                "[pipeline] Agent team execution failed, falling back to sequential pipeline: {}",
 971→                                e
 972→                            ),
 973→                        },
 974→                    );
 975→                    // Fall back to forge pipeline
 976→                    Self::run_forge_fallback(
 977→                        run_id,
 978→                        &project_path,
 979→                        &issue_title,
 980→                        &issue_description,
 981→                        &sandbox_clone,
 982→                        &running_processes,
 983→                        &db,
 984→                        &tx,
 985→                    )
 986→                    .await
 987→                }
 988→            };
 989→
 990→            // Clean up the process handle regardless of outcome
 991→            {
 992→                let mut processes = running_processes.lock().await;
 993→                processes.remove(&run_id);
 994→            }
 995→
 996→            // Check if already cancelled (e.g., by cancel() call)
 997→            {
 998→                let is_cancelled = match db
 999→                    .call(move |db| {
1000→                        Ok(db
1001→                            .get_pipeline_run(run_id)?
1002→                            .is_some_and(|r| r.status == PipelineStatus::Cancelled))
1003→                    })
1004→                    .await
1005→                {
1006→                    Ok(cancelled) => cancelled,
1007→                    Err(e) => {
1008→                        eprintln!(
1009→                            "[pipeline] run_id={}: DB error checking cancellation: {:#}",
1010→                            run_id, e
1011→                        );
1012→                        return;
1013→                    }
1014→                };
1015→                if is_cancelled {
1016→                    return;
1017→                }
1018→            }
1019→
1020→            match result {
1021→                Ok(summary) => {
1022→                    // Step 3: On success, create a PR if we have a branch (under project lock)
1023→                    if let Some(ref branch) = branch_name {
1024→                        let pr_result = {
1025→                            let git_lock = git_locks.get(&project_path).await;
1026→                            let _guard = git_lock.lock().await;
1027→                            create_pull_request(
1028→                                &project_path,
1029→                                branch,
1030→                                &issue_title,
1031→                                &issue_description,
1032→                            )
1033→                            .await
1034→                        };
1035→                        // git lock released — now safe to acquire DB lock
1036→                        match pr_result {
1037→                            Ok(pr_url) => {
1038→                                let pr_url_clone = pr_url.clone();
1039→                                if let Err(e) = db
1040→                                    .call(move |db| {
1041→                                        db.update_pipeline_pr_url(run_id, &pr_url_clone)
1042→                                    })
1043→                                    .await
1044→                                {
1045→                                    eprintln!(
1046→                                        "[pipeline] run_id={}: failed to update pipeline PR URL: {:#}",
1047→                                        run_id, e
1048→                                    );
1049→                                }
1050→                                broadcast_message(
1051→                                    &tx,
1052→                                    &WsMessage::PipelinePrCreated { run_id, pr_url },
1053→                                );
1054→                            }
1055→                            Err(e) => {
1056→                                eprintln!(
1057→                                    "[pipeline] run_id={}: PR creation failed (pipeline still completed): {:#}",
1058→                                    run_id, e
1059→                                );
1060→                            }
