13→
14→/// Async database handle wrapping a libsql Database.
15→///
16→/// Supports two modes:
17→/// - **Turso embedded replica** when TURSO_DATABASE_URL and TURSO_AUTH_TOKEN are set
18→/// - **Local SQLite** otherwise (dev/offline fallback)
19→#[derive(Clone)]
20→pub struct DbHandle {
21→    db: Database,
22→}
23→
24→impl DbHandle {
25→    /// Open a local-only SQLite database at the given path.
26→    pub async fn new_local(path: &Path) -> Result<Self> {
27→        let path_str = path.to_string_lossy().to_string();
28→        let db = Builder::new_local(&path_str)
29→            .build()
30→            .await
31→            .context("Failed to open local SQLite database")?;
32→        let handle = Self { db };
33→        handle.init().await?;
34→        Ok(handle)
35→    }
36→
37→    /// Open a Turso embedded replica with local file cache.
38→    pub async fn new_remote_replica(
39→        local_path: &Path,
40→        url: &str,
41→        token: &str,
42→    ) -> Result<Self> {
43→        let path_str = local_path.to_string_lossy().to_string();
44→        let db = Builder::new_remote_replica(
45→            &path_str,
46→            url.to_string(),
47→            token.to_string(),
48→        )
49→        .sync_interval(Duration::from_secs(60))
50→        .read_your_writes(true)
51→        .build()
52→        .await
53→        .context("Failed to open Turso embedded replica")?;
54→        let handle = Self { db };
55→        handle.init().await?;
56→        Ok(handle)
57→    }
58→
59→    /// Open an in-memory database (for testing).
60→    pub async fn new_in_memory() -> Result<Self> {
61→        let db = Builder::new_local(":memory:")
62→            .build()
63→            .await
64→            .context("Failed to open in-memory database")?;
65→        let handle = Self { db };
66→        handle.init().await?;
67→        Ok(handle)
68→    }
69→
70→    /// Get a new connection from the database.
71→    pub fn conn(&self) -> Result<Connection> {
72→        self.db
73→            .connect()
74→            .context("Failed to get database connection")
75→    }
76→
77→    /// Sync embedded replica with remote (no-op for local-only).
78→    pub async fn sync(&self) -> Result<()> {
79→        // sync() returns a result with replication info; we just need it to succeed
80→        let _ = self.db.sync().await;
81→        Ok(())
82→    }
83→
84→    /// Initialize pragmas and run migrations.
85→    async fn init(&self) -> Result<()> {
86→        let conn = self.conn()?;
87→        init_pragmas(&conn).await?;
88→        migrations::run_migrations(&conn).await?;
89→        Ok(())
90→    }
